// onchain-snapshotter — normalize the 4 source responses into snapshot rows.
// Canon (DB-SCHEMA §1/§8): value_raw is a STRING (never parse credits to a number); ts epoch-ms UTC.
const ts = Date.now();
const ts_bucket = Math.floor(ts / 3600000) * 3600000;

const status = $('PE status').first().json;
const shielded = $('PE shielded').first().json;

// ZecHub is served as text/plain by raw.githubusercontent, so n8n does NOT parse it:
// the node yields one item { data: "<raw JSON string>" }. Parse it and take the newest close.
function zecLast(nodeName) {
  const j = $(nodeName).first().json;
  let arr = j;
  if (j && typeof j.data === 'string') { try { arr = JSON.parse(j.data); } catch (e) { return null; } }
  else if (j && Array.isArray(j.data)) arr = j.data;
  if (!Array.isArray(arr)) return null;
  return arr.length ? arr[arr.length - 1] : null;
}
const zs = zecLast('ZecHub shielded');
const zt = zecLast('ZecHub total');

const height = (status && status.api && status.api.block && Number.isFinite(status.api.block.height))
  ? status.api.block.height : null;

const rows = [];
function push(source, asset, metric, valueRaw, valueNum, h, raw) {
  const n = (valueNum === null || valueNum === undefined || Number.isNaN(Number(valueNum))) ? null : Number(valueNum);
  rows.push({
    ts, ts_bucket, source, asset, metric,
    value_raw: String(valueRaw),
    value_num: n,
    height: (h === null || h === undefined) ? null : h,
    raw_json: raw === undefined ? null : JSON.stringify(raw),
    created_at: ts,
  });
}

// dash-platform <- platform-explorer /status
push('platform-explorer', 'dash-platform', 'identities_total', status.identitiesCount, status.identitiesCount, height, status);
push('platform-explorer', 'dash-platform', 'documents_total', status.documentsCount, status.documentsCount, height, status);
push('platform-explorer', 'dash-platform', 'data_contracts_total', status.dataContractsCount, status.dataContractsCount, height, status);
push('platform-explorer', 'dash-platform', 'platform_total_credits', status.totalCredits, status.totalCredits, height, status);

// dash-platform <- platform-explorer /transactions/shielded/statistic
push('platform-explorer', 'dash-platform', 'shielded_pool_balance_credits', shielded.poolBalance, shielded.poolBalance, height, shielded);
push('platform-explorer', 'dash-platform', 'shielded_total_in_credits', shielded.totalShieldedIn, shielded.totalShieldedIn, height, shielded);
push('platform-explorer', 'dash-platform', 'shielded_total_out_credits', shielded.totalShieldedOut, shielded.totalShieldedOut, height, shielded);
push('platform-explorer', 'dash-platform', 'shielded_transitions_total', shielded.transitionsCount, shielded.transitionsCount, height, shielded);

// zec <- ZecHub latest close point
if (zs && zs.supply !== undefined && zs.supply !== null) push('zechub', 'zec', 'zec_shielded_supply', zs.supply, zs.supply, null, zs);
if (zt && zt.supply !== undefined && zt.supply !== null) push('zechub', 'zec', 'zec_total_supply', zt.supply, zt.supply, null, zt);

if (rows.length === 0) {
  throw new Error('onchain-snapshotter: no rows produced (all sources empty)');
}
return [{ json: { count: rows.length, rows_json: JSON.stringify(rows) } }];
